class Solution:
    def basicCalculatorIV(self, expression, evalvars, evalints):
        evalmap = dict(zip(evalvars, evalints))
        tokens = expression.replace('(', ' ( ').replace(')', ' ) ').split()
        pos = 0
        def combine(a, b):
            r = dict(a)
            for k, v in b.items():
                r[k] = r.get(k, 0) + v
            return r
        def mul(a, b):
            r = {}
            for ka, va in a.items():
                for kb, vb in b.items():
                    key = tuple(sorted(ka + kb))
                    r[key] = r.get(key, 0) + va * vb
            return r
        def parse_atom():
            nonlocal pos
            t = tokens[pos]
            if t == '(':
                pos += 1
                res = parse_expr()
                pos += 1
                return res
            pos += 1
            if t.lstrip('-').isdigit():
                return {(): int(t)}
            if t in evalmap:
                return {(): evalmap[t]}
            return {(t,): 1}
        def parse_term():
            nonlocal pos
            res = parse_atom()
            while pos < len(tokens) and tokens[pos] == '*':
                pos += 1
                res = mul(res, parse_atom())
            return res
        def parse_expr():
            nonlocal pos
            res = parse_term()
            while pos < len(tokens) and tokens[pos] in ('+', '-'):
                op = tokens[pos]
                pos += 1
                rhs = parse_term()
                if op == '-':
                    rhs = {k: -v for k, v in rhs.items()}
                res = combine(res, rhs)
            return res
        poly = parse_expr()
        items = [(k, v) for k, v in poly.items() if v != 0]
        items.sort(key=lambda kv: (-len(kv[0]), kv[0]))
        out = []
        for k, v in items:
            out.append('*'.join([str(v)] + list(k)))
        return out

