class Solution:
    def basicCalculatorIV(self, expression, evalvars, evalints):
        evalmap = dict(zip(evalvars, evalints))
        s = expression
        i = 0
        n = len(s)
        def skip():
            nonlocal i
            while i < n and s[i] == ' ':
                i += 1
        def add(a, b, sign=1):
            r = dict(a)
            for k, v in b.items():
                r[k] = r.get(k, 0) + sign * v
            return r
        def mul(a, b):
            r = {}
            for ka, va in a.items():
                for kb, vb in b.items():
                    key = tuple(sorted(ka + kb))
                    r[key] = r.get(key, 0) + va * vb
            return r
        def atom():
            nonlocal i
            skip()
            if s[i] == '(':
                i += 1
                res = expr()
                skip()
                i += 1
                return res
            j = i
            while i < n and s[i] not in ' *()':
                i += 1
            tok = s[j:i]
            if tok.isdigit():
                return {(): int(tok)}
            if tok in evalmap:
                return {(): evalmap[tok]}
            return {(tok,): 1}
        def term():
            nonlocal i
            res = atom()
            while True:
                skip()
                if i < n and s[i] == '*':
                    i += 1
                    res = mul(res, atom())
                else:
                    break
            return res
        def expr():
            nonlocal i
            res = term()
            while True:
                skip()
                if i < n and s[i] in '+-':
                    op = s[i]
                    i += 1
                    rhs = term()
                    res = add(res, rhs, -1 if op == '-' else 1)
                else:
                    break
            return res
        poly = expr()
        items = [(k, v) for k, v in poly.items() if v != 0]
        items.sort(key=lambda kv: (-len(kv[0]), kv[0]))
        return ['*'.join([str(v)] + list(k)) for k, v in items]

