var basicCalculatorIV = function(expression, evalvars, evalints) {
    const evalmap = new Map();
    for (let k = 0; k < evalvars.length; k++) evalmap.set(evalvars[k], evalints[k]);
    const s = expression;
    const n = s.length;
    let i = 0;
    const skip = () => { while (i < n && s[i] === ' ') i++; };
    const addPoly = (a, b, sign) => {
        const r = new Map(a);
        for (const [k, v] of b) r.set(k, (r.get(k) || 0) + sign * v);
        return r;
    };
    const mulPoly = (a, b) => {
        const r = new Map();
        for (const [ka, va] of a) {
            for (const [kb, vb] of b) {
                const fa = ka === '' ? [] : ka.split(',');
                const fb = kb === '' ? [] : kb.split(',');
                const key = fa.concat(fb).sort().join(',');
                r.set(key, (r.get(key) || 0) + va * vb);
            }
        }
        return r;
    };
    const isDigits = (t) => t.length > 0 && /^[0-9]+$/.test(t);
    let atom, term, expr;
    atom = () => {
        skip();
        if (s[i] === '(') {
            i++;
            const res = expr();
            skip();
            i++;
            return res;
        }
        let j = i;
        while (i < n && s[i] !== ' ' && s[i] !== '*' && s[i] !== '(' && s[i] !== ')') i++;
        const tok = s.slice(j, i);
        const m = new Map();
        if (isDigits(tok)) m.set('', parseInt(tok, 10));
        else if (evalmap.has(tok)) m.set('', evalmap.get(tok));
        else m.set(tok, 1);
        return m;
    };
    term = () => {
        let res = atom();
        while (true) {
            skip();
            if (i < n && s[i] === '*') { i++; res = mulPoly(res, atom()); }
            else break;
        }
        return res;
    };
    expr = () => {
        let res = term();
        while (true) {
            skip();
            if (i < n && (s[i] === '+' || s[i] === '-')) {
                const op = s[i]; i++;
                const rhs = term();
                res = addPoly(res, rhs, op === '-' ? -1 : 1);
            } else break;
        }
        return res;
    };
    const poly = expr();
    const items = [];
    for (const [k, v] of poly) if (v !== 0) items.push([k, v]);
    const deg = (k) => k === '' ? 0 : k.split(',').length;
    items.sort((a, b) => {
        const da = deg(a[0]), db = deg(b[0]);
        if (da !== db) return db - da;
        return a[0] < b[0] ? -1 : a[0] > b[0] ? 1 : 0;
    });
    return items.map(([k, v]) => k === '' ? String(v) : [String(v)].concat(k.split(',')).join('*'));
};
